INSERT INTO Users
(
    Id,
    Email,
    FirstName,
    LastName,
    LoyaltyPoints,
    AvatarURL,
    PasswordHash,
    MFAType,
    TFASecret,
    IsVerified,
    Status,
    RoleId,
    LastLoginAt,
    CreatedAt,
    UpdatedAt
)
VALUES
(
    @Id,
    @Email,
    @FirstName,
    @LastName,
    @LoyaltyPoints,
    @AvatarURL,
    @PasswordHash,
    @MFAType,
    @TFASecret,
    @IsVerified,
    @Status,
    @RoleId,
    @LastLoginAt,
    @CreatedAt,
    @UpdatedAt
)

